-- Create Database

IF DB_ID('FinanceReconciliation') IS NULL

BEGIN
    CREATE DATABASE FinanceReconciliation;
END
GO

USE FinanceReconciliation;
GO

-- Create Tables

IF OBJECT_ID('dbo.Transactions', 'U') IS NOT NULL DROP TABLE dbo.Transactions;
IF OBJECT_ID('dbo.Settlements', 'U') IS NOT NULL DROP TABLE dbo.Settlements;
IF OBJECT_ID('dbo.AuditLog', 'U') IS NOT NULL DROP TABLE dbo.AuditLog;

CREATE TABLE dbo.Transactions (
    TransactionID INT PRIMARY KEY,
    UserID INT,
    Amount DECIMAL(10,2),
    Status VARCHAR(20),
    CreatedAt DATETIME
);

CREATE TABLE dbo.Settlements (
    SettlementID INT PRIMARY KEY,
    TransactionID INT,
    SettledAmount DECIMAL(10,2),
    SettledAt DATETIME
);

CREATE TABLE dbo.AuditLog (
    AuditID INT IDENTITY(1,1) PRIMARY KEY,
    EventTime DATETIME,
    Message NVARCHAR(500)
);
GO

